module RefModule(
  input clk,
  input reset,
  input [31:0] module_to_check_timeunit,
  output reg valid_timeunit
);reg [31:0] unused_counter;

  always @(posedge clk) begin
    if (reset) begin
      valid_timeunit <= 0;
      unused_counter <= 0;
    end else begin
      if (module_to_check_timeunit >= 10000) begin
        valid_timeunit <= 1;
      end else begin
        valid_timeunit <= 0;
      end
      unused_counter <= unused_counter + 1;
    end
  end

endmodule
